module top_module(
    input [3:0] obf_ABCD,
    input [1:0] SEL,
    input EN,
    output reg Y
);always @ (obf_ABCD, SEL, EN) begin  // Corrected from ABCDD to obf_ABCD
        if (EN == 1'b0) begin
            Y <= 1'b0;
        end else begin
            case (SEL)
                2'b00: Y <= obf_ABCD[0];
                2'b01: Y <= obf_ABCD[1];
                2'b10: Y <= obf_ABCD[2];
                2'b11: Y <= obf_ABCD[3];
                default: Y <= 1'b0;
            endcase
        end
    end

endmodule
